import Foundation

let questions12: [QuizQuestion] = [
QuizQuestion(id:901,question:"O que é o 'ministério da reconciliação' em 2 Coríntios 5:18-20?",options:["Um serviço eclesiástico apenas","Deus reconciliou o mundo consigo em Cristo e nos confiou 'o ministério da reconciliação' — tornando-nos 'embaixadores de Cristo' que suplicam: 'Reconciliai-vos com Deus'","Um papel apenas dos apóstolos","Um ministério apenas de missões externas"],correctIndex:1,explanation:"2 Co 5:18-20: a Igreja como embaixada de Cristo no mundo — embaixadores não têm mensagem própria mas da nação que representam. A mensagem é reconciliação, não condenação.",reference:"2 Coríntios 5:18-20",category:.geral,propheticMeaning:"'Em nome de Cristo, suplicamos' — a evangelização cristã não é exigência nem manipulação mas súplica: o apelo de quem sabe o que está em jogo e ama o ouvinte. O tom do evangelho é urgência amorosa, não ameaça coercitiva."),
QuizQuestion(id:902,question:"O que Paulo ensina sobre a 'couraça da fé e amor' em 1 Tessalonicenses 5:8?",options:["A fé e o amor são sentimentos","'Mas nós que somos do dia sejamos sóbrios, vestindo a couraça da fé e do amor, e por capacete, a esperança da salvação' — a tríade cristã (fé, amor, esperança) como armadura","A armadura é apenas física","Somente pastores precisam da armadura"],correctIndex:1,explanation:"1 Tessalonicenses 5:8: a tríade fé-amor-esperança (também em 1 Co 13:13 e 1 Ts 1:3) como armadura — a proteção espiritual dos 'filhos do dia' contra os perigos da escuridão moral e espiritual.",reference:"1 Tessalonicenses 5:8",category:.geral,propheticMeaning:"A 'couraça da fé e amor' como proteção dupla: a fé (voltada para Deus) e o amor (voltado para o próximo) juntos protegem o coração contra o medo, a idolatria e o egoísmo — as ameaças principais ao crente em qualquer época."),
QuizQuestion(id:903,question:"O que é a 'nova humanidade' em Efésios 2:15?",options:["Seres humanos melhorados geneticamente","Cristo criando 'em si mesmo, dos dois, um novo homem' — judeus e gentios reunidos numa nova entidade que transcende as antigas divisões étnico-religiosas: a Igreja como nova criação humana","Apenas os gentios convertidos","Um conceito não aplicável hoje"],correctIndex:1,explanation:"Efésios 2:15: 'hena kainon anthrōpon' — um homem novo (singular!) criado pela abolição das hostilidades entre judeus e gentios em Cristo. Não dois grupos unidos, mas uma nova entidade.",reference:"Efésios 2:15",category:.geral,propheticMeaning:"A 'nova humanidade' em Cristo é protótipo da nova criação escatológica — onde toda divisão humana (racial, cultural, de classe) será finalmente superada. A Igreja multicultural que demonstra unidade genuína é sinal antecipatório da nova criação."),
QuizQuestion(id:904,question:"O que Paulo diz sobre a 'prontidão' para o encontro com Cristo em Filipenses 4:5?",options:["Apenas se preocupe com a morte","'O Senhor está próximo' — a consciência da iminência da volta de Cristo motiva gentileza, ausência de ansiedade e oração em tudo (v.4-7)","A volta de Cristo é muito distante","Apenas líderes devem estar prontos"],correctIndex:1,explanation:"Filipenses 4:4-7: a próxima vinda do Senhor é mencionada entre 'alegrai-vos sempre' e 'em nada ansiosos' — a escatologia moldando a ética e a atitude do presente.",reference:"Filipenses 4:5",category:.geral,propheticMeaning:"'O Senhor está próximo' como antídoto à ansiedade: se o Senhor está perto, o julgamento das circunstâncias presentes é temporário e o auxílio divino é certo. A escatologia liberta o crente da tirania do momento presente."),
QuizQuestion(id:905,question:"O que Paulo diz sobre 'guardar a boa herança' em 2 Timóteo 1:14?",options:["Guarde os bens materiais da Igreja","'Guarda o bom depositum (parathēkēn) pelo Espírito Santo que habita em nós' — o depósito da fé (o evangelho e o ensino apostólico) deve ser guardado com fidelidade e transmitido","Inovar sempre no ensino cristão","Adapte a mensagem às culturas"],correctIndex:1,explanation:"2 Timóteo 1:14: 'parathēkē' (depósito confiado) — o evangelho como tesouro depositado que deve ser guardado (não adulterado) e transmitido (2 Tm 2:2: 'confiar a homens fiéis').",reference:"2 Timóteo 1:14; 2:2",category:.geral,propheticMeaning:"A 'boa herança' guardada pelo Espírito mostra que a preservação do evangelho não é esforço apenas humano — o mesmo Espírito que a inspirou a guarda através dos séculos. A tradição apostólica é protegida pelo Parácleto."),
QuizQuestion(id:906,question:"O que Paulo diz sobre o 'amor como propósito do mandamento' em 1 Timóteo 1:5?",options:["O mandamento se cumpre na obediência externa","'O fim do preceito é o amor proveniente de coração puro, boa consciência e fé sem fingimento' — o propósito de toda lei e instrução é produzir amor genuíno, não conformidade externa","O propósito do mandamento é punição","O mandamento é objetivo em si mesmo"],correctIndex:1,explanation:"1 Timóteo 1:5: o 'fim' (telos — alvo, meta, conclusão) de todo mandamento é amor — não legalismo que cumpre externamente sem transformação interior.",reference:"1 Timóteo 1:5",category:.geral,propheticMeaning:"O amor como 'telos' do mandamento confirma que toda a lei aponta para o amor (Mt 22:40; Rm 13:10). A formação espiritual que produz conformidade sem amor falhou; a que produz amor sem consciência também. O tripé (coração puro + boa consciência + fé sincera) gera amor genuíno."),
QuizQuestion(id:907,question:"O que é o 'profeta verdadeiro' versus 'falso profeta' nos Evangelhos e no AT?",options:["Apenas o AT tem falsos profetas","Jesus alertou: 'Acautelai-vos dos falsos profetas... pelos frutos os conhecereis' — o critério é o fruto (caráter, resultado) não os sinais sobrenaturais, pois 'milagres' podem ser feitos por falsos profetas também","Sinais milagrosos provam o profeta verdadeiro","Apenas os eruditos podem distinguir"],correctIndex:1,explanation:"Mateus 7:15-20; Deuteronômio 13:1-5: o falso profeta pode ter sinais, mas prega outros deuses; o cumprimento de profecias prova o profeta, mas o caráter e os frutos são o critério mais confiável.",reference:"Mateus 7:15-20; Deuteronômio 13:1-5",category:.geral,propheticMeaning:"'Pelos frutos os conhecereis' (Mt 7:16) é critério prático: o que a mensagem produz no ouvinte? Aproxima de Deus e do amor? Ou afasta? O poder sobrenatural não é prova de origem divina (Ap 13:13-14)."),
QuizQuestion(id:908,question:"O que é a 'oração no Espírito' em Judas 20 e Romanos 8:26?",options:["Falar em línguas apenas","'Orai no Espírito Santo' (Judas 20) — oração guiada, sustentada e expressada pelo Espírito Santo, incluindo o 'gemir inexprimível' de Romanos 8:26 quando não sabemos orar como deve ser","Uma prática apenas carismática","A oração em línguas substituindo a oração normal"],correctIndex:1,explanation:"Judas 20; Romanos 8:26: a oração no Espírito é tanto a oração articulada guiada pelo Espírito (Ef 6:18) quanto a intercessão além das palavras quando o sofrimento excede a capacidade de expressar.",reference:"Judas 20; Romanos 8:26",category:.geral,propheticMeaning:"O Espírito que 'intercede por nós com gemidos inexprimíveis' (Rm 8:26) garante que nossa oração mais imperfeita chega ao Pai transformada pela intercession divina. O crente mais fraco ora com o poder do Espírito."),
QuizQuestion(id:909,question:"O que Paulo diz sobre 'compreender o amor de Cristo' em Efésios 3:18-19?",options:["O amor de Cristo é completamente compreensível","'Que possais compreender, com todos os santos, qual é a largura, o comprimento, a altura e a profundidade do amor de Cristo, e conhecer o amor que excede todo o entendimento'","O amor de Cristo é incompreensível e, portanto, irrelevante","Somente os teólogos podem compreender"],correctIndex:1,explanation:"Efésios 3:18-19: o paradoxo — conhecer o amor que excede o conhecimento. A compreensão do amor de Cristo é aspiração que nunca chega ao fim; cada profundidade revela mais profundidade.",reference:"Efésios 3:18-19",category:.geral,propheticMeaning:"As quatro dimensões do amor de Cristo (largura, comprimento, altura, profundidade) apontam para a universalidade (toda a criação), a eternidade (sem começo nem fim), a transcendência (acima de tudo) e a intimidade (nas profundezas do sofrimento) desse amor."),
QuizQuestion(id:910,question:"O que João Batista proclamou como sua missão em João 3:30?",options:["Tornar-se igual a Jesus","'Convém que ele cresça e que eu diminua' — a declaração mais eloquente de humildade ministerial na Bíblia, reconhecendo que sua missão era preparar e diminuir","Competir com Jesus","Continuar sua missão indefinidamente"],correctIndex:1,explanation:"João 3:30: João Batista, questionado sobre Jesus, respondeu com esta declaração de autorrenúncia. Usando a imagem do amigo do noivo (v.29), se alegrou de ouvir a voz do noivo — sua alegria é completa ao diminuir.",reference:"João 3:29-30",category:.geral,propheticMeaning:"'Ele deve crescer, eu devo diminuir' (dei auxanein, eme de elattousthai) é a vocação do ministro cristão autêntico — não construir seu próprio reino mas apontar para o Rei. João o maior dos profetas (Mt 11:11) era o menor no reino porque se tornava o menor."),
QuizQuestion(id:911,question:"O que é o 'amor de Deus derramado nos corações' em Romanos 5:5?",options:["Um sentimento que geramos","'O amor de Deus foi derramado em nossos corações pelo Espírito Santo que nos foi dado' — a obra do Espírito que torna o amor de Deus experienciável internamente, base da esperança que não envergonha","Um dom apenas para apóstolos","Amor que depende das circunstâncias"],correctIndex:1,explanation:"Romanos 5:5: o Espírito Santo derramando (ekkechytai — passado perfeito, resultado permanente) o amor de Deus nos corações — não apenas conhecimento sobre o amor de Deus, mas experiência interior dele.",reference:"Romanos 5:5",category:.geral,propheticMeaning:"O amor de Deus derramado pelo Espírito é o que garante a esperança 'que não envergonha' — a base da esperança cristã não é otimismo sobre as circunstâncias mas certeza do amor de Deus experimentado internamente pelo Espírito."),
QuizQuestion(id:912,question:"O que é o 'dom de línguas' de Atos 2 comparado ao de 1 Coríntios 14?",options:["São idênticos","Em Atos 2, as línguas eram idiomas humanos conhecidos pelas multidões de vários países (dialekto); em 1 Coríntios 14, são linguagem não compreendida sem interpretação — possivelmente dois fenômenos ou o mesmo em contextos diferentes","O de Atos era superior","O de 1 Coríntios era superior"],correctIndex:1,explanation:"Atos 2:6-11: cada um ouvia 'em sua própria língua.' 1 Co 14:2: 'quem fala em língua não fala aos homens, mas a Deus, pois ninguém o entende.' O contexto e a função são diferentes.",reference:"Atos 2:6-11; 1 Coríntios 14:2",category:.geral,propheticMeaning:"A diversidade de expressão do dom em Atos e em 1 Coríntios revela que o Espírito é soberano na distribuição e expressão dos dons. O critério paulino não é a natureza exata do dom mas seu resultado: edificação e glorificação de Deus."),
QuizQuestion(id:913,question:"O que Paulo diz sobre 'andar no Espírito' versus 'andar na carne' em Romanos 8:4-5?",options:["São escolhas igualmente difíceis","'Para que a exigência justa da lei se cumprisse em nós, que andamos não segundo a carne, mas segundo o Espírito' — o crente habitado pelo Espírito pode cumprir o que a lei pedia mas era incapaz de produzir","A carne e o Espírito coexistem em equilíbrio","O andar no Espírito é apenas para momentos especiais"],correctIndex:1,explanation:"Romanos 8:4-5: 'andar' (peripatein) é metáfora para o modo de vida — os que são 'segundo o Espírito' têm sua mente e vida orientadas pelo Espírito, cumprindo naturalmente o que a lei exigia.",reference:"Romanos 8:4-9",category:.geral,propheticMeaning:"'A justiça da lei se cumprindo em nós' (Rm 8:4) é o objetivo da salvação — não apenas perdão mas transformação que produz a vida santa que a lei descrevia mas não podia criar. O Espírito realiza o que a lei exigia."),
QuizQuestion(id:914,question:"O que ensina o Salmo 91 sobre a proteção divina?",options:["Promessa de nunca sofrer dano","'O que habita no esconderijo do Altíssimo... dirá: O Senhor é o meu refúgio e a minha fortaleza, o meu Deus, em quem confio... nenhum mal te sucederá, nem praga alguma chegará à tua tenda'","Uma promessa de imunidade física absoluta","Apenas para Israel antigo"],correctIndex:1,explanation:"Salmo 91: promessa de proteção para 'quem habita no esconderijo do Altíssimo' — condicionada à habitação em Deus (v.1). Satanás citou este salmo tentando Jesus, que recusou torná-lo teste (Mt 4:6-7).",reference:"Salmos 91:1-2,10",category:.geral,propheticMeaning:"A recusa de Jesus de lançar-se do templo para 'testar' o Salmo 91 revela que as promessas de proteção divina são para quem habita em Deus pela fé, não para quem as manipula como fórmulas. Confiar em Deus inclui aceitar seu tempo e modo de proteger."),
QuizQuestion(id:915,question:"O que Paulo diz sobre a 'perseverança na oração' em Romanos 12:12?",options:["Ore apenas em crises","'Alegrai-vos na esperança, sede pacientes na tribulação, perseverai na oração' — a oração como prática constante que sustenta a alegria e a paciência nas dificuldades","A oração é apenas espiritual","A oração é desnecessária para os maduros"],correctIndex:1,explanation:"Romanos 12:12: a tríade esperança-tribulação-oração: a oração perseverante é o meio pelo qual a esperança é mantida sob tribulação — não eliminando a tribulação mas sustentando o crente através dela.",reference:"Romanos 12:12",category:.geral,propheticMeaning:"'Perseverai na oração' (proskarterountes — continuar com firmeza) indica que a oração não é impulso esporádico mas disciplina contínua. A perseverança na oração é inseparável da perseverança na fé."),
QuizQuestion(id:916,question:"O que é a 'libertação dos cativos' na proclamação de Jesus em Lucas 4:18?",options:["Libertação de prisioneiros físicos apenas","Jesus citando Isaías 61:1: 'O Espírito do Senhor está sobre mim... para proclamar libertação aos cativos... para dar liberdade aos oprimidos' — declarando que este texto se cumpria naquele momento","Uma promessa apenas para Israel","Um programa social sem dimensão espiritual"],correctIndex:1,explanation:"Lucas 4:18-21: a 'proclamação de Nazaré' como manifesto missionário de Jesus — libertação multidimensional (espiritual, social, física) que o Reino de Deus traz.",reference:"Lucas 4:18-21; Isaías 61:1",category:.geral,propheticMeaning:"'Hoje se cumpriu esta Escritura' (Lc 4:21) — Jesus afirmando ser ele mesmo o cumprimento do Servo de Isaías. O 'ano aceitável do Senhor' é o jubileu escatológico inaugurado pela vinda de Cristo: libertação real, agora, em Cristo."),
QuizQuestion(id:917,question:"O que Paulo ensina sobre a 'revelação de Cristo' como origem do seu evangelho em Gálatas 1:11-12?",options:["Paulo aprendeu com os outros apóstolos","'O evangelho por mim anunciado não é segundo o homem; pois não o recebi nem aprendi de homem algum, mas por revelação de Jesus Cristo'","Paulo criou seu próprio evangelho","Paulo adaptou o judaísmo"],correctIndex:1,explanation:"Gálatas 1:11-12: Paulo defende a origem divina e apostólica de seu evangelho — recebido diretamente por revelação de Cristo, não transmitido por tradição humana (embora confirmado pelos outros apóstolos — Gl 2:2).",reference:"Gálatas 1:11-12",category:.geral,propheticMeaning:"A revelação direta de Cristo a Paulo no caminho de Damasco (At 9) e 'no terceiro céu' (2 Co 12:2) fundamenta sua autoridade apostólica. Isso não contradiz a confirmação pelos outros apóstolos (Gl 2:9) mas estabelece a origem independente e divina de sua mensagem."),
QuizQuestion(id:918,question:"O que Paulo diz sobre o 'ensino saudável' em Tito 1:9?",options:["Qualquer ensino é aceitável na Igreja","O bispo deve 'reter a palavra fiel segundo a doutrina, para que seja poderoso tanto para exortar pelo são ensino como para convencer os que contradizem' — o ensino saudável é arma de defesa e ataque","O ensino não é prioritário","Apenas o amor importa, não a doutrina"],correctIndex:1,explanation:"Tito 1:9; 2:1: 'ensino saudável' (hygiainousē didaskalia — ensino que produz saúde espiritual) como responsabilidade do líder — tanto positivo (exortar) quanto apologético (refutar os que contradizem).",reference:"Tito 1:9; 2:1",category:.geral,propheticMeaning:"O 'ensino saudável' que 'adorna a doutrina de Deus' (Tt 2:10) pela vida ética mostra que doutrina e vida são inseparáveis — o ensino que não transforma não é genuinamente saudável, apenas informativo."),
QuizQuestion(id:919,question:"O que Paulo ensina sobre a 'manifestação do amor' em 1 Coríntios 13:4-7?",options:["O amor é apenas sentimento","'O amor é sofredor, é benigno; o amor não é invejoso; o amor não é arrogante... suporta tudo, crê tudo, espera tudo, suporta tudo' — o amor como ação e caráter, não sentimento","O amor depende de reciprocidade","Apenas casais precisam deste amor"],correctIndex:1,explanation:"1 Co 13:4-7: o hino do amor paulino descreve o amor não como emoção mas como série de ações e recusas de ação — 16 características, a maioria negativa ('não faz isso'), mostrando que amor real é decisão.",reference:"1 Coríntios 13:4-7",category:.geral,propheticMeaning:"Substituir 'amor' por 'Cristo' em 1 Co 13:4-7 revela o cumprimento perfeito: 'Cristo é sofredor, é benigno, Cristo não é invejoso...' — Jesus é a única pessoa que viveu plenamente este amor. O crente imita ao ser transformado por Cristo."),
QuizQuestion(id:920,question:"O que Paulo ensina sobre a 'perseverança dos santos' em 2 Timóteo 2:13?",options:["Que a infidelidade não tem consequências","'Se somos infiéis, ele permanece fiel, porque não pode negar a si mesmo' — a fidelidade de Deus é o fundamento da segurança da salvação, não a nossa consistência","Que podemos ser infiéis indefinidamente","Que Deus ignora nossa infidelidade"],correctIndex:1,explanation:"2 Timóteo 2:13: no contexto das condicionais (se renunciarmos... se negarmos... se suportarmos), a última é incondicional — mesmo nossa infidelidade não desfaz a fidelidade de Deus que 'não pode negar-se.'",reference:"2 Timóteo 2:13",category:.geral,propheticMeaning:"A fidelidade de Deus 'que não pode negar-se a si mesmo' é o fundamento mais sólido possível — a salvação ancorada não no crente (que oscila) mas no caráter imutável de Deus. Mas isso não elimina as consequências do abandono (v.12 — negar o Cristo resulta em ser negado)."),
QuizQuestion(id:921,question:"O que Apocalipse 12:11 diz sobre a vitória dos santos?",options:["A vitória vem pela força militar","'Eles o venceram pelo sangue do Cordeiro e pela palavra do seu testemunho, pois não amaram tanto a sua vida a ponto de recusar a morte'","A vitória vem pelo número","A vitória é apenas futura"],correctIndex:1,explanation:"Apocalipse 12:11: três armas da vitória: o sangue do Cordeiro (fundamento objetivo), o testemunho pessoal (expressão subjetiva), e disposição para morrer (rendição do auto-interesse). A vitória paradoxal através do martírio.",reference:"Apocalipse 12:11",category:.geral,propheticMeaning:"'Não amaram tanto a sua vida a ponto de recusar a morte' é a vitória pelo paradoxo da cruz — vencer morrendo, como Cristo. O mártir que morre pelo testemunho de Cristo replica o padrão do Cordeiro que 'venceu sendo morto' (Ap 5:5-6)."),
QuizQuestion(id:922,question:"O que João diz sobre a relação entre amor a Deus e amor ao irmão em 1 João 4:20?",options:["São dois amores independentes","'Se alguém diz: Amo a Deus, e odeia o seu irmão, é mentiroso; porque quem não ama o seu irmão a quem vê, não pode amar a Deus a quem não vê'","O amor a Deus é mais importante","O amor ao irmão substitui o amor a Deus"],correctIndex:1,explanation:"1 João 4:20: o amor ao irmão visível é o teste do amor a Deus invisível — não é possível ter amor genuíno a Deus que exclui o amor ao próximo.",reference:"1 João 4:20-21",category:.geral,propheticMeaning:"A lógica de 1 João 4:20 encerra o debate entre espiritualidade vertical e horizontal — não são alternativas mas inseparáveis. O amor que desceu de Deus ao crente deve fluir do crente ao próximo — a capilaridade do amor divino."),
QuizQuestion(id:923,question:"O que Paulo ensina sobre o 'fundamento único' em 1 Coríntios 3:11?",options:["A tradição da Igreja é o fundamento","'Ninguém pode pôr outro fundamento além do que já foi posto, o qual é Jesus Cristo' — o fundamento inalterável sobre o qual toda construção espiritual deve ser feita","O fundamento é a doutrina correta","O fundamento é a experiência espiritual"],correctIndex:1,explanation:"1 Co 3:11-15: o fundamento é Cristo; os materiais podem variar (ouro/prata/pedras preciosas vs madeira/feno/palha). O fogo do julgamento revelará a qualidade da construção sobre o fundamento imóvel.",reference:"1 Coríntios 3:11",category:.geral,propheticMeaning:"'Ninguém pode pôr outro fundamento' — a declaração mais exclusiva da teologia paulina. Toda a edificação espiritual, seja pessoal, eclesial ou teológica, deve ser feita sobre e em resposta ao mesmo fundamento: a pessoa e a obra de Jesus Cristo."),
QuizQuestion(id:924,question:"O que Paulo diz sobre a 'tranquilidade e quietude' como objetivo da vida cristã em 1 Timóteo 2:2?",options:["A agitação é normal para o cristão","Pedir a Deus para que possamos 'viver vida quieta e tranquila, em toda piedade e honestidade' — a tranquilidade como ambiente favorável à piedade e ao testemunho","A quietude é preguiça","A quietude é apenas para contemplativoss"],correctIndex:1,explanation:"1 Timóteo 2:1-4: Paulo instrui oração pelos reis e autoridades 'para que vivamos vida quieta e tranquila' — o ambiente de paz favorece tanto a piedade pessoal quanto o testemunho missionário.",reference:"1 Timóteo 2:1-4",category:.geral,propheticMeaning:"A 'vida tranquila e quieta' não é sem missão — é o ambiente que favorece que todos sejam salvos (v.4). A paz social e a liberdade religiosa são condições favoráveis à missão, razão pela qual Paulo instrui oração pelas autoridades."),
QuizQuestion(id:925,question:"O que Hebreus 12:11 ensina sobre a disciplina divina?",options:["Toda disciplina é punição irada","'Nenhuma disciplina parece agradável no momento, mas dolorosa; depois, porém, produz fruto pacífico de justiça para os que por ela foram exercitados'","A disciplina não produz fruto","A disciplina de Deus é diferente de qualquer sofrimento"],correctIndex:1,explanation:"Hebreus 12:5-11: a disciplina divina como prova de filiação amorosa — 'o Senhor disciplina aquele que ama' (citando Pv 3:11-12). Não é punição de inimigo mas formação de filho.",reference:"Hebreus 12:5-11",category:.geral,propheticMeaning:"'Fruto pacífico de justiça' como resultado da disciplina revela o objetivo formativo de Deus — não punição mas produção de caráter. O crente que passa pela disciplina com fé emerge com mais da justiça de Deus do que quando entrou."),
QuizQuestion(id:926,question:"O que Paulo diz sobre a 'generosidade da Igreja da Macedônia' como modelo em 2 Coríntios 8:1-5?",options:["A riqueza é necessária para a generosidade","As igrejas da Macedônia (Filipos, Tessalônica) deram além de suas posses e capacidade — 'primeiro deram-se a si mesmos ao Senhor' — a generosidade como consequência da doação de si mesmo","A Macedonia era uma exceção especial","A generosidade deve ser apenas da sobra"],correctIndex:1,explanation:"2 Co 8:1-5: o modelo macedônico — pobreza extrema gerando generosidade extrema, porque primeiro se deram ao Senhor. A ordem é: auto-rendição→generosidade, não riqueza→generosidade.",reference:"2 Coríntios 8:1-5",category:.geral,propheticMeaning:"'Deram-se a si mesmos ao Senhor' como origem da generosidade material confirma o princípio de Romanos 12:1 — o sacrifício vivo precede tudo. Quem se deu ao Senhor, dá facilmente do que tem; quem não se deu, segura mesmo na abundância."),
QuizQuestion(id:927,question:"O que ensina o Salmo 27:4 sobre o único desejo supremo?",options:["Ter riquezas e saúde","'Uma coisa pedi ao Senhor, e a buscarei: que possa morar na casa do Senhor todos os dias da minha vida, para contemplar a beleza do Senhor e perscrutar o seu templo'","Vencer os inimigos","Ter uma longa vida"],correctIndex:1,explanation:"Salmo 27:4: Davi reduz todos os desejos a um — habitação na presença de Deus e contemplação de sua beleza. A presença de Deus como único desejo que subsume todos os outros.",reference:"Salmos 27:4",category:.geral,propheticMeaning:"'A beleza do Senhor' (noam YHWH — a graça/deleite divino) é o objeto da contemplação. Jesus em Betânia aprovou Maria que escolheu 'a boa parte' — contemplar — contra Marta que estava ocupada servindo. O serviço flui da contemplação, não a substitui."),
QuizQuestion(id:928,question:"O que Paulo diz sobre 'ser crucificado com Cristo' em Gálatas 2:20?",options:["Uma experiência mística especial","'Já estou crucificado com Cristo; e vivo, não mais eu, mas Cristo vive em mim; e a vida que agora vivo na carne, vivo pela fé no Filho de Deus que me amou e se entregou a si mesmo por mim'","Uma metáfora sem implicações","A morte física do apóstolo"],correctIndex:1,explanation:"Gálatas 2:20: a identidade cristã fundamental — o 'eu' antigo foi crucificado (co-crucificação), Cristo vive no crente, e a vida presente é exercício de fé no Filho que amou pessoalmente e se entregou especificamente.",reference:"Gálatas 2:20",category:.geral,propheticMeaning:"'Que me amou e a si mesmo se entregou por mim' (singular!) — Paulo personalizando o evangelho. A morte de Cristo não foi apenas por uma massa humana abstrata, mas por cada um individualmente. O 'por mim' é o coração da fé pessoal."),
QuizQuestion(id:929,question:"O que é a 'revelação natural' e seus limites segundo Romanos 1?",options:["A natureza revela tudo sobre Deus","A criação revela o poder e a divindade eternos de Deus — tornando todos responsáveis — mas não revela o evangelho, o nome de Cristo, nem o caminho da salvação; para isso é necessária a revelação especial","A natureza é suficiente para salvar","Deus não se revela pela natureza"],correctIndex:1,explanation:"Romanos 1:19-20: a revelação natural é universal (todos a recebem), responsabilizadora (torna todos sem desculpa), mas insuficiente para salvar (não revela o evangelho).",reference:"Romanos 1:19-20",category:.geral,propheticMeaning:"O limite da revelação natural (suficiente para responsabilizar, insuficiente para salvar) fundamenta a urgência da missão — se a natureza bastasse, não seria necessário 'ir e fazer discípulos de todas as nações.' A missão existe porque a revelação especial é necessária para a salvação."),
QuizQuestion(id:930,question:"O que Paulo diz sobre a 'adoção aguardada' em Romanos 8:23?",options:["A adoção já está completa","'Nós mesmos, que temos as primícias do Espírito, gememos em nosso íntimo, aguardando a adoção, a redenção do nosso corpo' — a adoção tem dimensão presente (espírito) e futura (corpo)","A adoção não inclui o corpo","A adoção ocorre apenas na morte"],correctIndex:1,explanation:"Romanos 8:23: a tensão 'já/ainda não' da adoção — já somos filhos (Rm 8:15) mas a adoção plena aguarda a redenção do corpo na ressurreição.",reference:"Romanos 8:23",category:.geral,propheticMeaning:"'Aguardando a adoção' quando já somos filhos revela que nossa filiação atual é real mas incompleta — como filhos adotados que vivem na casa do Pai mas ainda não receberam a herança plena. A ressurreição é a adoção completa: corpos glorificados à imagem do Filho."),
QuizQuestion(id:931,question:"Qual é o chamado dos primeiros discípulos em Marcos 1:17?",options:["'Sigam-me e eu vos farei ricos'","'Vinde após mim, e eu farei que sejais pescadores de homens' — o chamado combina: vir a Cristo (relação), seguir após ele (discipulado) e ser transformado por ele para transformar outros (missão)","'Sejam meus servos'","'Estudem a lei comigo'"],correctIndex:1,explanation:"Marcos 1:17: o chamado de Pedro e André usa a metáfora da pesca (familiar para eles) para descrever a missão — a formação do discipulado e a missão são inseparáveis desde o início.",reference:"Marcos 1:17",category:.geral,propheticMeaning:"'Eu farei' — a transformação de pescadores em pescadores de homens é obra de Cristo, não dos discípulos. O seguimento de Cristo naturalmente produz o tipo de pessoa que atrai e ganha outros para o Rei. Formação e missão fluem do mesmo relacionamento."),
QuizQuestion(id:932,question:"O que João diz sobre o 'nascimento de Deus' em 1 João 3:9?",options:["Os crentes nunca pecam","'Qualquer um que é nascido de Deus não pratica pecado, porque a semente de Deus permanece nele; e não pode continuar pecando, pois nasceu de Deus' — a vida divina implantada torna impossível o padrão contínuo de pecado","Os crentes são perfeitos","O pecado é impossível para crentes"],correctIndex:1,explanation:"1 João 3:9: 'não pratica pecado' (presente contínuo — não comete como padrão de vida) — não perfecionismo absoluto (1 Jo 1:8-10 admite pecados) mas incapacidade de viver permanentemente no pecado.",reference:"1 João 3:9",category:.geral,propheticMeaning:"A 'semente de Deus' (sperma autou — a natureza de Deus, o Espírito, a Palavra) permanecendo no crente é o princípio da nova vida que torna o padrão de vida pecaminosa incompatível com quem nasceu de Deus. Não impecabilidade mas nova direção."),
QuizQuestion(id:933,question:"O que é a 'esperança viva' em 1 Pedro 1:3?",options:["Uma esperança incerta","'Deus nos regenerou para uma esperança viva pela ressurreição de Jesus Cristo dentre os mortos' — esperança fundamentada na ressurreição histórica, objetiva e verificável de Cristo","Uma esperança apenas espiritual","Uma esperança que pode desaparecer"],correctIndex:1,explanation:"1 Pedro 1:3: 'esperança viva' (zōsan elpida) — não esperança morta de especulação humana, mas esperança que vive porque seu fundamento vive: Cristo ressurreto.",reference:"1 Pedro 1:3",category:.geral,propheticMeaning:"A esperança cristã é 'viva' porque é ancorada numa pessoa viva (Cristo ressurreto) e num evento histórico (a ressurreição). Não é otimismo sobre o futuro baseado em tendências, mas certeza fundamentada no que Deus já fez."),
QuizQuestion(id:934,question:"Qual é o último versículo de Apocalipse com o convite final?",options:["'Aleluia, o Senhor reina'","'Aquele que testifica estas coisas diz: Certamente venho em breve. Amém. Vem, Senhor Jesus. A graça do Senhor Jesus seja com todos'","'E o Anjo disse: Estas palavras são verdadeiras'","'Guardai as palavras desta profecia'"],correctIndex:1,explanation:"Apocalipse 22:20-21: o último testemunho de Cristo ('venho em breve') e a última oração da Bíblia ('Vem, Senhor Jesus') e a bênção final de graça — a Bíblia terminando com graça, esperança e anseio pela vinda do Senhor.",reference:"Apocalipse 22:20-21",category:.geral,propheticMeaning:"A última palavra da Bíblia é 'graça' (charis) — a Bíblia que começa com criação pela graça termina com graça. O cânon fecha como abriu: com o Deus de graça estendendo-se à humanidade. A história da redenção é história da graça do princípio ao fim."),
QuizQuestion(id:935,question:"Quem foram as doze tribos de Israel e sua origem?",options:["Os doze filhos de Moisés","Os doze filhos de Jacó (Israel): Rúben, Simeão, Levi, Judá, Issacar, Zebulom, José, Benjamim, Dã, Naftali, Gade e Aser — mas na terra, Levi recebeu cidades, e José foi dividido em Efraim e Manassés","Os doze amigos de Davi","Os doze discípulos de Elias"],correctIndex:1,explanation:"Gênesis 49: as 12 tribos de Israel derivam dos 12 filhos de Jacó. Levi (sacerdotal) não recebeu território; José se dividiu em Efraim e Manassés, mantendo o número 12 territorialmente.",reference:"Gênesis 49:1-28",category:.genesis,propheticMeaning:"Os 12 tribos correspondem aos 12 apóstolos (Mt 19:28) — Jesus reconstituindo o Israel escatológico em torno de si. Os 144.000 de Apocalipse 7 com as 12 tribos representam a totalidade do povo de Deus em figuras simbólicas."),
QuizQuestion(id:936,question:"O que foi a bênção de Jacó sobre Judá em Gênesis 49:10?",options:["Uma bênção sobre riqueza","'O cetro não se afastará de Judá... até que venha Siló; e a ele obedecerão os povos' — profecia do governante messiânico da tribo de Judá","Uma bênção sobre terras","Uma bênção sobre o sacerdócio"],correctIndex:1,explanation:"Gênesis 49:10: 'Siló' (de quem é o cetro, ou o pacificador) é identificado como profecia messiânica — o governante eterno da tribo de Judá a quem os povos obedecerão. Cumprido em Cristo, o 'Leão de Judá' (Ap 5:5).",reference:"Gênesis 49:10; Apocalipse 5:5",category:.genesis,propheticMeaning:"'Leão de Judá' (Ap 5:5) cita diretamente a bênção de Jacó — Judá como leão (Gn 49:9) e o governante messiânico que vem de Judá. Jesus, da tribo de Judá e descendente de Davi, é o cumprimento desta profecia patriarcal."),
QuizQuestion(id:937,question:"O que Josué 1:9 promete ao crente no enfrentamento de desafios?",options:["'Lute com suas próprias forças'","'Não to ordenei eu? Esforça-te e tem bom ânimo; não te atemorizes, nem te espantes, porque o Senhor teu Deus é contigo por onde quer que andares'","'Nunca terás desafios'","'Pede auxílio a outros'"],correctIndex:1,explanation:"Josué 1:9: a palavra de Deus a Josué ao assumir a liderança após Moisés — coragem fundamentada não na ausência de ameaças mas na presença de Deus ('o Senhor teu Deus contigo').",reference:"Josué 1:9",category:.profetas,propheticMeaning:"'Não te atemorizes' (al-taarotz — não sejas quebrado/perturbado) pressupõe que haverá coisas atemorizantes — Deus não promete ausência de desafios mas sua presença nos desafios. A coragem bíblica é confiança em Deus, não ausência de medo."),
QuizQuestion(id:938,question:"O que é a 'lei do amor' (ágape) como cumprimento da lei em Romanos 13:8-10?",options:["O amor substitui completamente a lei","'Não deveis nada a ninguém, a não ser o amor mútuo; pois quem ama o próximo cumpriu a lei... o amor não opera mal ao próximo; portanto, o amor é o cumprimento da lei'","A lei e o amor são idênticos","O amor e a lei são independentes"],correctIndex:1,explanation:"Romanos 13:8-10: o amor como 'plērōma da lei' (cumprimento, plenitude) — não abolindo a lei mas realizando-a por dentro o que a lei exigia de fora. Quem genuinamente ama não rouba, não mata, não adultera.",reference:"Romanos 13:8-10",category:.geral,propheticMeaning:"O amor como 'plērōma' da lei confirma que a lei e o evangelho não são opostos mas continuum — a lei descrevia a vida amorosa; o evangelho pela graça e Espírito torna possível viver essa vida de amor que a lei requeria."),
QuizQuestion(id:939,question:"O que Paulo diz sobre a 'identidade em Cristo' superando a identidade étnica em Colossenses 3:11?",options:["A identidade étnica é mais importante","'Não há grego nem judeu, circuncisão nem incircuncisão, bárbaro, cita, escravo, livre; mas Cristo é tudo em todos' — a identidade em Cristo é mais fundamental que qualquer identidade social ou étnica","As distinções étnicas são eliminadas fisicamente","A identidade cristã é apenas espiritual"],correctIndex:1,explanation:"Colossenses 3:11: Paulo abrangendo o máximo de diversidade possível (étnica, religiosa, cultural, social) para afirmar que 'Cristo é tudo em todos' os supera.",reference:"Colossenses 3:11",category:.geral,propheticMeaning:"'Cristo é tudo em todos' (panta kai en pasin Christos) — não diversidade eliminada mas Cristo como o denominador comum que transforma a diversidade em unidade. A Igreja não é monocultura mas Christ-cultura."),
QuizQuestion(id:940,question:"O que Paulo diz sobre a 'corrida para o prêmio' em Filipenses 3:14?",options:["O prêmio é a salvação que garantimos","'Prossigo para o alvo, para o prêmio da soberana vocação de Deus em Cristo Jesus' — Paulo, esquecendo o que ficou para trás e avançando para o que está à frente, correndo para a meta","O prêmio não importa","A corrida é apenas sobre obras"],correctIndex:1,explanation:"Filipenses 3:12-14: Paulo em sua maturidade ainda se considera não perfeito, mas pressionando para a frente — 'esquecendo o que está para trás e avançando para o que está adiante.'",reference:"Filipenses 3:12-14",category:.geral,propheticMeaning:"'Esquecendo o que está para trás' — tanto os fracassos (não carregar culpa) quanto os sucessos (não descansar em conquistas passadas). O olhar do atleta espiritual está fixo no alvo (Cristo), não no percurso percorrido."),
QuizQuestion(id:941,question:"O que Paulo ensina sobre 'viver para Cristo' após a conversão em Gálatas 2:19?",options:["Morremos para a lei pela nossa vontade","'Pela lei morri para a lei, a fim de viver para Deus. Já estou crucificado com Cristo' — a morte para a lei não foi por decisão própria mas pela própria lei que condenou e Cristo cumpriu","A lei ainda governa o crente","O crente escolhe quando viver para Cristo"],correctIndex:1,explanation:"Gálatas 2:19: 'pela lei morri para a lei' — a lei ao condenar Jesus na cruz (Gl 3:13) e o crente morrendo com Cristo fica 'morto para a lei' que foi satisfeita. A morte para a lei é o que permite viver para Deus.",reference:"Gálatas 2:19",category:.geral,propheticMeaning:"O paradoxo paulino: a lei me condenou (morte para a lei); Cristo cumpriu a lei morrendo (cumprimento da lei); eu morri com Cristo (liberação da lei). O resultado: 'vivo para Deus' — não sem lei mas sob o governo do amor do Espírito."),
QuizQuestion(id:942,question:"O que Paulo ensina sobre a 'esperança da ressurreição' como fundamento da vida moral em 1 Coríntios 15:32?",options:["A esperança é apenas motivacional","'Se os mortos não ressuscitam, comamos e bebamos, porque amanhã morreremos' — a negação da ressurreição destrói o fundamento da ética cristã de longo prazo","A ética prescinde da escatologia","O prazer imediato é mais racional se não há ressurreição"],correctIndex:1,explanation:"1 Co 15:32: Paulo usa a reductio ad absurdum — se não há ressurreição, o epicurismo é a conclusão lógica. A ressurreição fundamenta todo o edifício ético e escatológico cristão.",reference:"1 Coríntios 15:32",category:.geral,propheticMeaning:"A ressurreição como fundamento ético revela que a moralidade cristã não é pragmática (o que produz bem-estar social) nem kantiana (dever abstrato) mas escatológica — agimos em vista da avaliação divina e da ressurreição vindoura."),
QuizQuestion(id:943,question:"O que Apocalipse 3:20 diz sobre Cristo à porta?",options:["Cristo forçará a entrada","'Eis que estou à porta e bato; se alguém ouvir a minha voz e abrir a porta, entrarei em sua casa e cenarei com ele e ele comigo'","Cristo entra mesmo sem convite","A porta está permanentemente aberta"],correctIndex:1,explanation:"Apocalipse 3:20: escrito à Igreja de Laodicéia (morna, autossuficiente) — Cristo do lado de fora batendo. O paradoxo: o Senhor de tudo aguarda a abertura voluntária da porta.",reference:"Apocalipse 3:20",category:.geral,propheticMeaning:"Cristo batendo do lado de fora da Igreja (não do lado de fora do coração do inconverso) é advertência à comunidade cristã morna — ele pode ser excluído de dentro da religiosidade. A ceia prometida ao que abre é imagem da comunhão restaurada."),
QuizQuestion(id:944,question:"O que Paulo diz sobre a 'moderação do pregador' em 1 Coríntios 2:1-4?",options:["Seja o mais eloquente possível","Paulo em Corinto 'não fui com sublimidade de palavras ou de sabedoria... meu discurso e minha pregação não foram com palavras persuasivas de sabedoria humana, mas em demonstração do Espírito e de poder'","Use toda a retórica disponível","A habilidade retórica é necessária para o evangelho"],correctIndex:1,explanation:"1 Co 2:1-4: Paulo deliberadamente evitou retórica impressionante em Corinto (que valorizava a eloquência sofística) para que a fé dos coríntios repousasse no poder de Deus, não na sabedoria humana.",reference:"1 Coríntios 2:1-5",category:.geral,propheticMeaning:"'Em demonstração do Espírito e de poder' — o evangelho eficaz não depende da habilidade do pregador (que pode impressionar sem transformar) mas do poder do Espírito. A fraqueza do mensageiro pode ser instrumento do poder de Deus."),
QuizQuestion(id:945,question:"O que Paulo ensina sobre 'gloriar-se na cruz' em Gálatas 6:14?",options:["Gloriar-se nos resultados","'Longe esteja de mim gloriar-me senão na cruz de nosso Senhor Jesus Cristo' — a cruz como único motivo de glorificação, em contraste com aqueles que se gloriam na circuncisão (v.12-13)","Gloriar-se na doutrina correta","Gloriar-se nos dons espirituais"],correctIndex:1,explanation:"Gálatas 6:14: Paulo encerrando a carta sobre liberdade com esta declaração pessoal — seu único troféu é a cruz, não a circuncisão, não as conversões, não as experiências espirituais.",reference:"Gálatas 6:14",category:.geral,propheticMeaning:"O cristão que 'gloriar-se' na cruz como seu único motivo encontra liberdade de toda a comparação e competição ministerial. O 'escândalo' da cruz (Gl 5:11) e a 'glória' da cruz (Gl 6:14) coexistem — o que é escândalo para o mundo é glória para quem compreendeu."),
QuizQuestion(id:946,question:"O que ensina o Salmo 119 sobre o amor à lei de Deus?",options:["A lei é um fardo","'Oh! Quanto amo a tua lei! É a minha meditação todo o dia' (v.97) — o mais longo salmo expressa paixão pela Palavra de Deus como lanterna, tesouro, deleite e guia de toda a vida","A lei é apenas regras","A lei é inferior ao NT"],correctIndex:1,explanation:"Salmo 119 (176 versículos em acróstico hebraico): a meditação sobre cada aspecto da Palavra de Deus — lei, testemunhos, preceitos, estatutos, mandamentos, juízos — celebrados como deleite, não fardo.",reference:"Salmos 119:97,105",category:.geral,propheticMeaning:"'Lâmpada para os meus pés e luz para o meu caminho' (Sl 119:105) — a Palavra como guia pessoal e revelação do próximo passo (lâmpada) e do caminho total (luz). Deleitar-se na lei é antecipar o prazer de andar segundo a vontade de Deus."),
QuizQuestion(id:947,question:"O que Paulo ensina sobre o 'cuidado com os fracos' em Romanos 14-15?",options:["Os fracos devem crescer sozinhos","'Nós, os que somos fortes, devemos suportar as fraquezas dos que são fracos e não agradar a nós mesmos. Cada um de nós agrade ao próximo no que é bom para edificação'","Os fortes podem desprezar os fracos","Os fracos são um peso desnecessário"],correctIndex:1,explanation:"Romanos 15:1-3: o forte suportando o fraco à imitação de Cristo — 'pois também Cristo não se agradou a si mesmo.' O serviço ao fraco é imitar Cristo que serviu não para agradar-se.",reference:"Romanos 15:1-3",category:.geral,propheticMeaning:"'Cristo não se agradou a si mesmo' (Rm 15:3, citando Sl 69:9) como modelo para os 'fortes' — não apenas paciência condescendente mas imagem de Cristo que esvaziou-se. Cuidar do fraco é kenose aplicada ao cotidiano comunitário."),
QuizQuestion(id:948,question:"O que é o 'dom de ensinar' na Igreja segundo Romanos 12:7?",options:["Habilidade pedagógica apenas","O dom espiritual de explicar a Palavra de Deus de forma que edifica e transforma — 'se alguém tem dom de ensinar, que ensine' — distinto da profecia, é sistemático e formativo","Ensinar é papel apenas de pastores","O ensino é menos importante que os dons miraculosos"],correctIndex:1,explanation:"Romanos 12:7; Efésios 4:11: o dom de ensinar como parte do equipamento da Igreja — os 'pastores-mestres' (Ef 4:11) são dado à Igreja para 'equipar os santos para o ministério.'",reference:"Romanos 12:7; Efésios 4:11-12",category:.geral,propheticMeaning:"O ensino como dom para 'equipar os santos para o ministério' revela que o professor-pastor não é o único ministro — seu trabalho é habilitar todos os membros. O sucesso do mestre é quando os alunos fazem o que ele ensinou."),
QuizQuestion(id:949,question:"O que é o 'pecado de omissão' em Tiago 4:17?",options:["Um conceito não bíblico","'Aquele que sabe fazer o bem e não o faz, isso lhe é pecado' — não apenas transgressões ativas mas falhas em fazer o bem quando a oportunidade existe","Apenas os pecados ativos importam","Omissão não é pecado moral"],correctIndex:1,explanation:"Tiago 4:17: o pecado de omissão — a responsabilidade de agir quando há capacidade e oportunidade de fazer o bem. O padrão cristão não é apenas 'não faça o mal' mas 'faça o bem.'",reference:"Tiago 4:17",category:.geral,propheticMeaning:"O pecado de omissão é o pecado do servo que enterrou o talento (Mt 25:25-27) e do sacerdote e levita que passaram pelo lado do ferido (Lc 10:31-32). A responsabilidade cristã inclui o que fazemos e o que deixamos de fazer quando deveríamos agir."),
QuizQuestion(id:950,question:"O que é a 'diligência' no ministério como virtude em Romanos 12:8?",options:["Trabalhar em excesso","'Quem exerce presidência, com diligência (spoude — zelo ardente); quem pratica misericórdia, com alegria' — o dom de liderança exercido com fervor e urgência","Trabalhar sem descanso","A diligência é apenas para os líderes formais"],correctIndex:1,explanation:"Romanos 12:8: 'spoude' (diligência, ardor, fervor) — o exercício dos dons de liderança e misericórdia com empenho e alegria, não com preguiça ou relutância.",reference:"Romanos 12:8",category:.geral,propheticMeaning:"'Não sede tardios no fervor' (Rm 12:11 — mē okneroi tē spoudē) — o fervor (spoude) como antídoto à preguiça espiritual. A diligência no ministério reflete a 'servidão ao Senhor' (v.11) que não trata o trabalho de Deus com negligência."),
QuizQuestion(id:951,question:"Qual é o fruto do Espírito contrário à impaciência em Gálatas 5:22?",options:["Força","Paciência (makrothymia — longanimidade, longo sofrimento) e longanimidade (hypomonē) — dois aspectos do 'fruto do Espírito': makrothymia (paciência com pessoas) e hypomonē (perseverança em circunstâncias)","Paz","Gentileza"],correctIndex:1,explanation:"Gálatas 5:22: 'makrothymia' — literalmente 'longa ira' (mãos longas, demora em irritar-se) é paciência com pessoas difíceis; contrasta com a 'rixas, iracúndia, discórdias' das obras da carne (v.20).",reference:"Gálatas 5:22",category:.geral,propheticMeaning:"Makrothymia (paciência com pessoas) é atributo de Deus (Rm 2:4; 1 Tm 1:16) — 'longanime' para com os pecadores, aguardando o arrependimento. O Espírito produz no crente um reflexo desta paciência divina nas relações humanas."),
QuizQuestion(id:952,question:"O que Paulo diz sobre a 'veneração dos ídolos' como participação demoníaca em 1 Coríntios 10:20?",options:["Os ídolos são inofensivos","'O que os gentios sacrificam, sacrificam-no a demônios, e não a Deus; e não quero que tenhais comunhão com os demônios' — participar em festas idólatras é comunhão com espíritos demoníacos","Os ídolos são apenas símbolos culturais","A idolatria é pecado apenas intelectual"],correctIndex:1,explanation:"1 Co 10:19-21: Paulo distingue o ídolo (nada real — v.19) do demônio que está por trás (real — v.20). A idolatria é real em seus efeitos espirituais, mesmo que o ídolo seja apenas pedra ou madeira.",reference:"1 Coríntios 10:19-21",category:.geral,propheticMeaning:"A idolatria como 'comunhão com demônios' revela que não há neutralidade espiritual — qualquer adoração que não vai a Deus vai para algum outro poder, consciente ou inconscientemente. 'Não podeis beber do cálice do Senhor e do cálice dos demônios' (1 Co 10:21)."),
QuizQuestion(id:953,question:"O que é a 'sujeição mútua' em Efésios 5:21?",options:["A sujeição é apenas unilateral","'Sujeitai-vos uns aos outros no temor de Cristo' — o princípio que precede as instruções sobre casamento, família e trabalho em Efésios 5-6, fundamento de todas as relações cristãs","A sujeição é apenas dos inferiores","Apenas o crente fraco deve sujeitar-se"],correctIndex:1,explanation:"Efésios 5:21: a sujeição mútua ('uns aos outros') como princípio abrangente de toda a vida comunitária cristã — motivada pelo temor de Cristo, não pelo temor das consequências.",reference:"Efésios 5:21",category:.geral,propheticMeaning:"'No temor de Cristo' como motivação da sujeição mútua revela que as hierarquias humanas (cônjuge, pai-filho, empregado-empregador) são relativizadas pelo senhorio de Cristo sobre todos. Todos se sujeitam a todos por amor ao mesmo Senhor."),
QuizQuestion(id:954,question:"O que Paulo ensina sobre a 'gratidão como estilo de vida' em Colossenses 3:17?",options:["Agradeça apenas nas orações formais","'Tudo o que fizerdes, seja em palavra ou em obra, fazei tudo em nome do Senhor Jesus, dando por ele graças a Deus Pai' — toda a vida impregnada de gratidão, não apenas momentos especiais","Apenas os cultos requerem gratidão","A gratidão é sentimento, não prática"],correctIndex:1,explanation:"Colossenses 3:17: 'tudo' (panta) — palavras E obras, em nome de Jesus, com gratidão. A gratidão como coloração de toda a vida, não apenas como resposta a bênçãos específicas.",reference:"Colossenses 3:17",category:.geral,propheticMeaning:"Gratidão em tudo (Cl 3:17) é o resultado de perceber que 'todo dom perfeito é lá do alto' (Tg 1:17) — reconhecer a origem divina de toda coisa boa transforma o ordinário em oportunidade de gratidão."),
QuizQuestion(id:955,question:"O que João revela sobre o 'amor por decreto' em João 13:34?",options:["O amor é espontâneo ou não é real","'Um mandamento novo vos dou: Que vos ameis uns aos outros; como eu vos amei, vós também deveis amar-vos uns aos outros' — o amor é mandamento, não apenas sentimento opcional","Jesus não pode comandar o amor","O amor cristão não tem modelo"],correctIndex:1,explanation:"João 13:34: o amor como 'mandamento novo' (entolēn kainēn) — novo não porque o amor não existia (Lv 19:18) mas porque tem novo padrão ('como eu vos amei') e novo fundamento (a morte de Cristo).",reference:"João 13:34",category:.geral,propheticMeaning:"'Como eu vos amei' é o padrão radicalmente novo — não 'como você gostaria de ser amado' nem 'como você pode amar naturalmente' mas à medida do amor sacrificial de Cristo. O mandamento cria a obrigação; a graça provê a capacidade pelo Espírito."),
QuizQuestion(id:956,question:"O que é a 'admoestação fraterna' em Mateus 18:15-17?",options:["Criticar publicamente o irmão","O processo de reconciliação cristã: 1) conversar a sós; 2) levar uma ou duas testemunhas; 3) levar à Igreja — o objetivo é 'ganhar o teu irmão' (v.15), não puni-lo","Julgar e excluir imediatamente","Ignorar os pecados dos irmãos"],correctIndex:1,explanation:"Mateus 18:15-17: a disciplina eclesiástica como processo de restauração — começa privado, escala gradualmente, com o objetivo de ganhar o irmão de volta.",reference:"Mateus 18:15-17",category:.geral,propheticMeaning:"'Para que ganhos o teu irmão' (v.15) — a meta é restauração, não punição. O processo gradual dá oportunidade de arrependimento em cada etapa. A disciplina que não visa restauração distorce o modelo de Cristo que veio para 'buscar e salvar o perdido.'"),
QuizQuestion(id:957,question:"O que Paulo diz sobre a 'pureza da mente' em Filipenses 4:8?",options:["Ignore o que entra na mente","'Tudo o que é verdadeiro, tudo o que é honesto, tudo o que é justo, tudo o que é puro, tudo o que é amável, tudo o que é de boa fama, nisso pensai' — a gestão cristã dos pensamentos","A mente não precisa de guarda","Apenas pensamentos espirituais formais importam"],correctIndex:1,explanation:"Filipenses 4:8: Paulo lista oito categorias do verdadeiro, honesto, justo, puro, amável, de boa fama, virtuoso e louvável — o alimento mental que o cristão deve buscar deliberadamente.",reference:"Filipenses 4:8",category:.geral,propheticMeaning:"A gestão dos pensamentos em Fp 4:8 complementa a renovação da mente de Rm 12:2 — a transformação da mente requer tanto o que ela processa (Fp 4:8) quanto o princípio que a governa (a Palavra e o Espírito). O que alimentamos nossa mente molda quem somos."),
QuizQuestion(id:958,question:"O que Paulo ensina sobre a 'semeadura e colheita' em Gálatas 6:7-8?",options:["A Lei da Semeadura é garantia de prosperidade","'Não vos enganeis; Deus não se deixa zombar; pois o homem colherá o que semear. Quem semeia para a carne, da carne colherá corrupção; mas quem semeia para o Espírito, do Espírito colherá vida eterna'","A colheita não segue a semeadura","Deus interfere na colheita sem relação à semeadura"],correctIndex:1,explanation:"Gálatas 6:7-8: o princípio de semeadura e colheita como lei moral — não para a prosperidade material (hermenêutica equivocada) mas para o caráter e a destinação eterna.",reference:"Gálatas 6:7-8",category:.geral,propheticMeaning:"'Deus não se deixa zombar' (ou mykterizō — literalmente 'não se levanta o nariz contra') — a tentativa de enganar Deus semeando para o egoísmo e esperando colheita espiritual é auto-enganação. O caráter que semeamos agora é o caráter que seremos."),
QuizQuestion(id:959,question:"O que Paulo diz sobre a 'espera paciente da glória' em Romanos 8:25?",options:["Não espere passivamente","'Se esperamos o que não vemos, com paciência o aguardamos' — a esperança do que não se vê (corpo ressurreto, nova criação) requer paciência ativa enquanto gememos com a criação","A glória já foi revelada plenamente","A espera é desnecessária"],correctIndex:1,explanation:"Romanos 8:25: a esperança bíblica não é dos que veem mas dos que creem sem ver — e a paciência (hypomonē) é a virtude que a esperança requer enquanto aguarda.",reference:"Romanos 8:25",category:.geral,propheticMeaning:"'Com paciência o aguardamos' — a esperança cristã não é passiva nem ansiosa, mas confiante e paciente. Como o agricultor que semeia e aguarda a colheita (Tg 5:7), o crente semeia fidelidade e aguarda a colheita escatológica com firmeza."),
QuizQuestion(id:960,question:"O que ensina o Salmo 16 sobre a herança eterna no Senhor?",options:["As riquezas materiais são a herança","'O Senhor é a porção da minha herança e do meu cálice... os meus limites caíram em lugares deleitosos' — Deus mesmo como a herança do crente, e 'não deixarás que o teu Santo veja corrupção' (citado em At 2:27)","A herança é a terra de Canaã apenas","A herança é apenas espiritual no futuro"],correctIndex:1,explanation:"Salmo 16: Davi expressando que Deus é sua porção e herança, com segurança diante da morte: 'a minha carne reposará em segurança.' Pedro cita v.10 em Pentecostes como profecia da ressurreição de Jesus.",reference:"Salmos 16:5-6,10-11; Atos 2:27",category:.geral,propheticMeaning:"'Não deixarás que o teu Santo veja corrupção' (Sl 16:10) não se cumpriu em Davi (que 'viu corrupção' — At 2:29-31) mas em Jesus, revelando que o Salmo é profecia do Messias. Pedro: Davi 'foi profeta e sabia' que falava de Cristo."),
QuizQuestion(id:961,question:"O que é o 'tempo de orar' segundo Daniel 6?",options:["Daniel orava quando convinha","Daniel continuou orando três vezes ao dia de frente a Jerusalém mesmo após o decreto que tornava a oração a qualquer deus um crime punível na cova dos leões — e foi protegido por Deus","Daniel interrompeu a oração por prudência","A oração é negociável nas crises"],correctIndex:1,explanation:"Daniel 6:10: Daniel ciente do decreto, foi para casa, abriu as janelas voltadas para Jerusalém e orou como de costumbre — a fidelidade na oração não negociada mesmo sob ameaça de morte.",reference:"Daniel 6:10-22",category:.profetas,propheticMeaning:"Daniel orando com 'as janelas abertas' (v.10) — não exibição desafiadora, mas recusa de esconder sua fé por conveniência. A oração de Daniel não variou com as circunstâncias; as circunstâncias variaram por causa de sua oração constante."),
QuizQuestion(id:962,question:"O que Jesus disse sobre a ovelha que estava perdida e as 99 deixadas (Mateus 18:12-14)?",options:["Proteja sempre as 99","'Não é a vontade do vosso Pai celestial que se perca um só destes pequeninos' — o coração de Deus que valoriza cada indivíduo e vai buscar o perdido","As 99 são mais importantes","Apenas as ovelhas fortes importam"],correctIndex:1,explanation:"Mateus 18:12-14: a parábola no contexto da proteção dos 'pequeninos' — Deus como pastor que não aceita a perda de nenhum, e sua alegria ao encontrar o perdido.",reference:"Mateus 18:12-14",category:.geral,propheticMeaning:"'A vontade do Pai' que nenhum se perca (Mt 18:14) e a oração de Jesus 'que não percas nenhum dos que me deste' (Jo 17:12) revelam que a preservação dos crentes é vontade declarada de Deus — fundamento da doutrina da perseverança dos santos."),
QuizQuestion(id:963,question:"O que Paulo ensina sobre o 'amor que não busca seus interesses' em Filipenses 2:4?",options:["Cuide apenas de si mesmo","'Não atendendo cada um aos seus próprios interesses, mas cada qual também aos interesses dos outros' — a ética kenótica inspirada pelo exemplo de Cristo que não se agradou a si mesmo","O auto-interesse é natural e aceitável","Os interesses pessoais devem ser completamente ignorados"],correctIndex:1,explanation:"Filipenses 2:4: o equilíbrio paulino — não apenas aos 'outros' mas 'também aos outros' (kai ta heteron) — a consideração dos interesses alheios sem negar completamente o próprio ser.",reference:"Filipenses 2:4",category:.geral,propheticMeaning:"A ética do 'também aos outros' é mais sustentável que o 'apenas aos outros' — Paulo não exige auto-aniquilação mas expansão do interesse para além de si mesmo. O modelo é Cristo que, existindo 'em forma de Deus,' não excluiu os nossos interesses."),
QuizQuestion(id:964,question:"O que é a 'missão aos confins da terra' em Atos 1:8?",options:["Um projeto opcional para voluntários","'Recebereis poder, havendo o Espírito Santo descido sobre vós, e sereis minhas testemunhas em Jerusalém, em toda a Judeia e Samaria, e até aos confins da terra'","A missão é apenas local","A missão terminou com os apóstolos"],correctIndex:1,explanation:"Atos 1:8: o plano geográfico e missiológico de Lucas-Atos — de Jerusalém (At 1-7), Judeia e Samaria (At 8-12), até os confins da terra (At 13-28, culminando em Roma).",reference:"Atos 1:8",category:.atos,propheticMeaning:"'Confins da terra' (eschatou tēs gēs) encoa Isaías 49:6 — o mandato do Servo de ser luz 'até os confins da terra.' Jesus transferindo o mandato do Servo-Messias à sua Igreja, habilitada pelo mesmo Espírito que estava sobre ele (Is 61:1; Lc 4:18)."),
QuizQuestion(id:965,question:"O que Paulo diz sobre o 'dom de governar' na Igreja em 1 Coríntios 12:28?",options:["Governar é papel apenas de pastores","'E a uns pôs Deus na Igreja: primeiro apóstolos, depois profetas, em terceiro lugar mestres, depois milagres, depois dons de curar, socorros, governos, variedades de línguas' — governos como dom espiritual","Os dons administrativos não são espirituais","A administração é humana e não espiritual"],correctIndex:1,explanation:"1 Co 12:28: 'kyberneseis' (de onde vem 'cibernética') — a habilidade de guiar, pilotar, administrar como dom espiritual da Igreja. O bom governo eclesiástico é obra do Espírito.",reference:"1 Coríntios 12:28",category:.geral,propheticMeaning:"A inclusão de 'governos' (administração) na lista dos dons espirituais de 1 Co 12 revela que a gestão eficaz da Igreja é obra do Espírito tanto quanto a cura ou a profecia. Separar 'ministério espiritual' de 'administração' é falsa dicotomia."),
QuizQuestion(id:966,question:"O que Paulo diz sobre 'fazer o bem a todos' em Gálatas 6:10?",options:["Faça bem apenas aos crentes","'Enquanto temos oportunidade, façamos o bem a todos, mas principalmente aos da família da fé' — a responsabilidade de fazer bem é universal, com prioridade para a comunidade cristã","O bem aos não-crentes é desnecessário","O bem é apenas para méritos espirituais"],correctIndex:1,explanation:"Gálatas 6:10: o bem (kakon — bem prático) a todos (pantas) sem discriminação, com atenção especial ('principalmente') à comunidade cristã — a 'família da fé.'",reference:"Gálatas 6:10",category:.geral,propheticMeaning:"'Enquanto temos oportunidade' (kairon — o momento propício) é urgência escatológica — o tempo de fazer o bem é agora, antes que o 'kairon' passe. A consciência da brevidade da vida cristifica cada oportunidade de bem."),
QuizQuestion(id:967,question:"O que é a 'teologia da glória' que João contrasta em seu Evangelho?",options:["Um conceito apenas de Lutero","João usa o conceito de 'glória' (doxa) paradoxalmente: a glória de Jesus é revelada na cruz ('a hora da glorificação' — Jo 12:23-24,32) — a glória por meio do sofrimento e morte, invertendo a expectativa humana","A glória é apenas no céu","A glória é apenas nos milagres"],correctIndex:1,explanation:"João 12:23-24,32: 'a hora de ser glorificado o Filho do Homem' = a hora da cruz. 'Quando eu for levantado da terra, atrairei todos a mim' — a exaltação na cruz, não após ela.",reference:"João 12:23-24,32",category:.geral,propheticMeaning:"A glória na cruz (Jo 12:23) é o paradoxo central de João — onde o mundo vê desonra, Deus revela a maior glória. A 'hora' (de Caná a Getsêmani) é sempre a hora da cruz, a hora da glória máxima do Filho."),
QuizQuestion(id:968,question:"O que Paulo diz sobre a 'obra de Cristo em nós' versus 'nossa obra' em Filipenses 2:12-13?",options:["A obra é inteiramente humana","'Operai a vossa salvação com temor e tremor; porque Deus é o que opera em vós tanto o querer como o efetuar, segundo a sua boa vontade' — a paradoxo de responsabilidade humana e soberania divina simultâneas","A obra é inteiramente divina sem responsabilidade humana","As duas são contraditórias"],correctIndex:1,explanation:"Filipenses 2:12-13: o paradoxo resolvido pela sequência — 'operai vós' (responsabilidade) 'PORQUE Deus opera' (fundamento). A obra humana é estimulada, não negada, pela obra divina.",reference:"Filipenses 2:12-13",category:.geral,propheticMeaning:"'Deus que opera em vós o querer' — até o desejo de fazer o bem é iniciativa divina. Isso não elimina a vontade humana mas a fundamenta: o crente quer o que Deus quer porque Deus criou esse querer nele. Graça e responsabilidade são inseparáveis."),
QuizQuestion(id:969,question:"O que é a 'firmeza na fé' contra os adversários em Filipenses 1:27-28?",options:["Evitar todo conflito","'Permaneceis firmes em um mesmo espírito... combatendo unanimemente pela fé do evangelho; sem que em coisa alguma vos intimideis com os adversários' — a firmeza coletiva na missão sem medo dos opositores","Ceder às pressões","Defender apenas por meios políticos"],correctIndex:1,explanation:"Filipenses 1:27-28: a vida digna do evangelho expressa em firmeza coletiva (en heni pneumati — num só espírito) e sem intimidação — 'para eles é sinal de perdição, mas para vós, de salvação.'",reference:"Filipenses 1:27-28",category:.geral,propheticMeaning:"A firmeza dos crentes diante dos adversários sendo 'sinal de perdição para eles e de salvação para vós' revela que a coragem cristã não é apenas virtude pessoal mas testemunho público — a fé que não vacila proclama que há algo que vale mais que a autopreservação."),
QuizQuestion(id:970,question:"O que Paulo diz sobre 'ser tudo para todos' em 1 Coríntios 9:22-23?",options:["Não tenha princípios firmes","'Fiz-me tudo para todos, para por todos os meios chegar a salvar alguns. E tudo faço por causa do evangelho, para dele me tornar participante' — flexibilidade cultural sem comprometer o evangelho","Comprometa o evangelho para alcançar as pessoas","A contextualização é errada"],correctIndex:1,explanation:"1 Co 9:22-23: Paulo renunciando a direitos legítimos (sustento material, estilo de vida cultural) para remover barreiras ao evangelho — contextualização sem sincretismo.",reference:"1 Coríntios 9:22-23",category:.geral,propheticMeaning:"'Por todos os meios' (pantōs) — Paulo ajustou estilo sem ajustar substância. Com judeus como judeu (lei), com sem-lei como sem-lei (liberdade), mas sempre 'na lei de Cristo' (v.21). A contextualização bíblica muda a embalagem, nunca o conteúdo."),
QuizQuestion(id:971,question:"O que Paulo ensina sobre a 'separação do mal' em 2 Coríntios 6:17?",options:["Isolamento total do mundo","'Saí do meio delas e separai-vos diz o Senhor; e não toqueis o que é imundo, e eu vos receberei' — separação do mal (idolatria, imoralidade, alianças comprometedoras) não do mundo em geral","Apenas separação mental","A separação é apenas espiritual sem implicações práticas"],correctIndex:1,explanation:"2 Co 6:14-7:1: Paulo citando Isaías 52:11 exorta a separação de 'jugo desigual' — não isolamento cultural total mas recusa de comprometimentos com o mal.",reference:"2 Coríntios 6:17",category:.geral,propheticMeaning:"A tensão 'no mundo mas não do mundo' (Jo 17:15-16) é a postura cristã permanente. A separação de 2 Co 6:17 não é monasticismo mas recusa de comprometimentos que comprometam a testemunha — o 'sair' do mal, não do mundo."),
QuizQuestion(id:972,question:"O que João diz sobre a 'vitória sobre o mundo' em 1 João 5:4-5?",options:["O mundo nunca pode ser vencido","'Tudo o que é nascido de Deus vence o mundo; e esta é a vitória que venceu o mundo: a nossa fé. E quem vence o mundo senão aquele que crê que Jesus é o Filho de Deus?'","Apenas alguns crentes vencem","A vitória é automática sem fé"],correctIndex:1,explanation:"1 João 5:4-5: a vitória sobre o mundo é coletiva ('tudo que é nascido de Deus') e pessoal ('aquele que crê') — o instrumento é a fé, especificamente fé na identidade de Jesus como Filho de Deus.",reference:"1 João 5:4-5",category:.geral,propheticMeaning:"'A fé que venceu o mundo' (aoristo — já venceu) é a mesma fé dos mártires de Apocalipse 12:11 que 'venceram pelo sangue do Cordeiro.' A vitória é do Cordeiro e é compartilhada pelos que nele confiam — a fé participa da vitória já conquistada."),
QuizQuestion(id:973,question:"Qual é a última exortação de Hebreus aos leitores?",options:["'Sede perfeitos'","'Mas o Deus de paz que ressuscitou dos mortos o nosso Senhor Jesus... vos aperfeiçoe em toda boa obra, para que façais a sua vontade, operando em vós o que é agradável diante dele por Jesus Cristo'","'Fujam do mundo'","'Obedeçam aos líderes cegamente'"],correctIndex:1,explanation:"Hebreus 13:20-21: a bênção final — o 'Deus de paz' que ressuscitou Jesus como 'Pastor das ovelhas' age 'em vós' para aperfeiçoar — a santificação como obra de Deus operada em nós.",reference:"Hebreus 13:20-21",category:.geral,propheticMeaning:"'Operando em vós o que é agradável' — o aperfeiçoamento cristão é obra de Deus, não conquista humana. A bênção sacerdotal de Hebreus não encoraja auto-aperfeiçoamento mas confiança na obra do Deus que ressuscitou Jesus: se ressuscitou o morto, pode aperfeiçoar o fraco."),
QuizQuestion(id:974,question:"O que é a 'leitura de Esdras da lei' em Neemias 8 e seu efeito?",options:["Uma aula educacional comum","Esdras leu a lei publicamente do alvorecer ao meio-dia em praça pública; o povo chorou ao ouvir as palavras da lei; Esdras e Neemias disseram: 'a alegria do Senhor é a vossa força'; o povo celebrou a festa com grande alegria","Uma cerimônia religiosa rotineira","Um evento sem impacto espiritual"],correctIndex:1,explanation:"Neemias 8:1-12: a grande convocação — Esdras leu, os levitas explicaram (v.8 — 'claramente, com o sentido'), o povo chorou de compunção e foi instruído a celebrar, não lamentar.",reference:"Neemias 8:1-12",category:.profetas,propheticMeaning:"'A alegria do Senhor é a vossa força' (Nq 8:10) dita a um povo que chorou — Deus transformando o lamento em celebração pela mesma Palavra que produziu convicção. A Palavra que convence também consola; a que corrige também restaura."),
QuizQuestion(id:975,question:"O que é a 'promessa do Espírito' a toda carne em Joel 2:28?",options:["Uma promessa apenas para sacerdotes","'Depois disso, derramarei o meu Espírito sobre toda a carne; vossos filhos e vossas filhas profetizarão... até sobre os servos e as servas derramarei o meu Espírito'","Uma promessa apenas para Israel étnico","Uma promessa apenas para o fim dos tempos"],correctIndex:1,explanation:"Joel 2:28-29: a democratização do Espírito — sem distinção de gênero (filhos e filhas), idade (velhos e jovens) ou classe (servos e servas). Cumprida inicialmente em Pentecostes (At 2:17-21).",reference:"Joel 2:28-29; Atos 2:17-21",category:.profetas,propheticMeaning:"'Toda carne' (kol basar) é a expressão mais inclusiva possível — o Espírito derramado na era messiânica não será privilégio de alguns mas herança de todos os filhos de Deus. A experiência do Espírito que antes era de profetas especiais agora é de todos os crentes."),
QuizQuestion(id:976,question:"O que ensina o Salmo 73 sobre a inveja dos prósperos ímpios?",options:["Os ímpios sempre sofrem","Asafe quase tropeçou vendo a prosperidade dos ímpios ('tive inveja dos arrogantes') até entrar no santuário de Deus e ver o fim deles: 'puseste-os em lugares escorregadios... em um momento caíram, foram destruídos'","A prosperidade prova a piedade","A fé não tem nada a ver com prosperidade material"],correctIndex:1,explanation:"Salmo 73: o problema da prosperidade dos ímpios é resolvido pela perspectiva do santuário — lá Asafe viu não apenas o presente deles mas o fim. A perspectiva eterna transforma a interpretação das circunstâncias presentes.",reference:"Salmos 73:2-3,17-19",category:.geral,propheticMeaning:"'Até que entrei no santuário de Deus' (Sl 73:17) — a solução para a inveja e o escândalo com a prosperidade dos ímpios é a perspectiva sub specie aeternitatis (sob a perspectiva da eternidade). O que parece vantagem temporal é desvantagem eterna."),
QuizQuestion(id:977,question:"O que Paulo diz sobre a 'espada do Espírito' como única arma ofensiva da armadura em Ef 6:17?",options:["A espada é a nossa fé","'A espada do Espírito, que é a palavra de Deus' — a única arma ofensiva da armadura espiritual; todas as outras são defensivas (cinto, couraça, calçados, escudo, capacete)","As línguas são a espada","A oração é a espada"],correctIndex:1,explanation:"Efésios 6:17: 'machairan tou pneumatos ho estin rēma Theou' — a espada do Espírito é a Palavra de Deus (rēma — palavra dita/proclamada). Jesus usou a espada da Palavra nas tentações ('está escrito').",reference:"Efésios 6:17",category:.geral,propheticMeaning:"'Está escrito' (Mateus 4:4,7,10) — Jesus derrotando as três tentações com a espada da Palavra. O modelo perfeito do uso da armadura espiritual: confrontar cada mentira do inimigo com a verdade específica da Palavra de Deus."),
QuizQuestion(id:978,question:"O que ensina o Salmo 2 sobre o Messias reinante?",options:["O Messias virá como servo apenas","'Eu pus o meu Rei no meu santo monte de Sião... Tu és meu Filho; hoje eu te gerei... pede-me, e eu te darei as nações como herança'  — a entronização real do Filho messiânico sobre toda a terra","O Messias reinará apenas em Israel","O Rei de Sião é apenas Davi"],correctIndex:1,explanation:"Salmo 2: o rei entronizado em Sião que recebe as nações como herança é interpretado no NT como cumprido em Cristo — Paulo em At 13:33, Hebreus 1:5 e 5:5 citam 'Tu és meu Filho, hoje te gerei.'",reference:"Salmos 2:7-8; Atos 13:33",category:.geral,propheticMeaning:"'Hoje te gerei' (Sl 2:7) aplicado à ressurreição (At 13:33) revela que o 'hoje' messiânico é o momento da entronização de Cristo — a ressurreição como intronização do Filho que recebe o domínio universal profetizado no Salmo."),
QuizQuestion(id:979,question:"Qual é o chamado de Isaías ao servir como profeta em Isaías 6?",options:["Um chamado fácil e animador","Após a visão da santidade divina e a purificação com a brasa do altar, Isaías ouviu: 'A quem mandarei, e quem irá por nós?' e respondeu: 'Eis-me aqui, envia-me a mim' — o chamado através da purificação","Isaías foi forçado a profetizar","O chamado foi apenas para Isaías"],correctIndex:1,explanation:"Isaías 6:1-8: visão (v.1-4) → convicção (v.5) → purificação (v.6-7) → chamado (v.8) → resposta (v.8). O padrão do chamado profético: encontro com Deus→consciência do pecado→purificação→missão.",reference:"Isaías 6:1-8",category:.profetas,propheticMeaning:"O chamado de Isaías revela que a missão autêntica começa com o encontro transformador com Deus, não com ambição ou competência. 'Eis-me aqui' vem depois de 'sou desfeito' e 'tuas iniquidades foram tiradas' — a humildade e a purificação precedem o envio."),
QuizQuestion(id:980,question:"O que Paulo diz sobre 'orar em toda oração e súplica' em Efésios 6:18?",options:["Ore apenas nos cultos","'Orando em todo tempo com toda a oração e súplica no Espírito Santo, e para isso vigiando com toda perseverança e súplica por todos os santos' — oração como cobertura constante e intercessão mútua","Ore apenas por si mesmo","A oração é menos importante que a ação"],correctIndex:1,explanation:"Efésios 6:18: quatro 'todos' — todo tempo, toda oração/súplica, toda perseverança, todos os santos — a totalidade e a universalidade da cobertura de oração que Paulo exorta.",reference:"Efésios 6:18",category:.geral,propheticMeaning:"A oração de Efésios 6:18 encerra a armadura de Deus — como a respiração que anima o soldado que usa a armadura. Sem oração, a armadura é pesada e ineficaz; com oração, cada peça é investida de poder e propósito divinos."),
QuizQuestion(id:981,question:"O que Jesus disse sobre 'perder a própria alma' em Marcos 8:36?",options:["A alma não tem valor comparável","'Que aproveitará ao homem ganhar o mundo inteiro, se perder a sua alma? Ou que dará o homem em troca da sua alma?'","As riquezas são iguais à alma","A alma pode ser recuperada após a perda"],correctIndex:1,explanation:"Marcos 8:36-37: a questão mais importante da vida — o valor incomparável da alma diante de tudo que o mundo pode oferecer. Nenhuma posse, poder ou prazer compensa a perda da vida eterna.",reference:"Marcos 8:36-37",category:.geral,propheticMeaning:"'Que dará o homem em troca de sua alma?' — a resposta é implícita: nada. Não há moeda de troca pela alma perdida. Este versículo é o argumento mais poderoso para a prioridade absoluta da salvação sobre qualquer conquista temporal."),
QuizQuestion(id:982,question:"O que Paulo diz sobre 'agir sem murmuração nem contenda' em Filipenses 2:14-15?",options:["A murmuração é natural","'Fazei tudo sem murmurações nem contendas, para que sejais irrepreensíveis e sinceros, filhos de Deus inculpáveis no meio de uma geração perversa e corrupta'","A murmuração é apenas problema menor","Apenas os líderes devem evitar a murmuração"],correctIndex:1,explanation:"Filipenses 2:14-15: a ausência de murmuração como testemunho — em contraste com Israel que murmurou no deserto, a Igreja sem murmuração 'resplandece como luminares no mundo.'",reference:"Filipenses 2:14-15",category:.geral,propheticMeaning:"'Luminares no mundo' (phōstēres en kosmō) — a ausência de murmuração e contenda é tão notável que faz a Igreja brilhar como estrelas numa geração perversa e corrupta. A gratidão e a paz que o evangelho produz é o testemunho mais visível."),
QuizQuestion(id:983,question:"O que é o 'caminho mais excelente' que Paulo propõe em 1 Coríntios 12:31?",options:["Os dons espirituais","'Ainda vos mostrarei um caminho mais excelente' — introduzindo o hino do amor (1 Co 13) como o 'caminho' superior a todos os dons espirituais","A sabedoria intelectual","A experiência mística"],correctIndex:1,explanation:"1 Co 12:31b: o 'caminho mais excelente' é o amor (agapē) de 1 Co 13 — não um dom entre outros mas o meio pelo qual todos os dons devem ser exercidos.",reference:"1 Coríntios 12:31",category:.geral,propheticMeaning:"O amor como 'caminho mais excelente' que supera até os dons do Espírito revela a hierarquia de valores de Paulo: os dons são temporários ('cessarão' — 1 Co 13:8); o amor é eterno. Dons sem amor são ruído; amor sem dons é suficiente."),
QuizQuestion(id:984,question:"O que Paulo diz sobre 'dar de si mesmo' como modelo apostólico em 1 Tessalonicenses 2:8?",options:["O ministro deve manter distância dos discipulados","'Assim tão grande é o nosso amor por vós que estávamos dispostos a dar-vos não somente o evangelho de Deus, mas também as nossas próprias vidas'","O ministério é apenas transmissão de informação","Manter distância profissional é necessário"],correctIndex:1,explanation:"1 Tessalonicenses 2:8: o modelo ministerial de Paulo — não apenas a mensagem mas a própria vida. A kerygma encarnada: o mensageiro como parte da mensagem.",reference:"1 Tessalonicenses 2:8",category:.geral,propheticMeaning:"'Nossas próprias vidas' como parte do que é dado aos discipulados transforma o ministério de transmissão de informação em transmissão de vida. É a encarnação do evangelho — como Jesus não apenas anunciou a graça mas foi a graça."),
QuizQuestion(id:985,question:"O que Paulo diz sobre a 'espera da esperança da justiça' em Gálatas 5:5?",options:["Trabalhe para a justiça","'Nós, pelo Espírito, com base na fé, aguardamos a esperança da justiça' — a justificação presente (pela fé) aguardando a glorificação futura (a justiça completa), sustentada pelo Espírito","A justiça já é completa agora","A justiça é apenas futura"],correctIndex:1,explanation:"Gálatas 5:5: o crente vive na tensão 'já/ainda não' — já justificado pela fé, aguardando a plena manifestação da justiça na glorificação, movido pelo Espírito.",reference:"Gálatas 5:5",category:.geral,propheticMeaning:"'Pelo Espírito, com base na fé' — a vida cristã inteira (fé + Espírito) está orientada para a esperança futura da glória. A justificação presente e a glorificação futura são os dois polos que estruturam a existência cristã no mundo."),
QuizQuestion(id:986,question:"O que Paulo diz sobre o 'julgamento de si mesmo' em 1 Coríntios 11:31?",options:["Julgue-se duramente para ser perfeito","'Se nós nos julgássemos a nós mesmos, não seríamos julgados' — o auto-exame constante que reconhece e confessa o pecado evita a disciplina divina corretiva","O auto-julgamento é impossível","Só Deus pode julgar"],correctIndex:1,explanation:"1 Co 11:31-32: o auto-exame preventivo (especialmente antes da Ceia do Senhor — v.28) como forma de evitar a disciplina do Senhor que 'castiga para que não sejamos condenados com o mundo.'",reference:"1 Coríntios 11:28-32",category:.geral,propheticMeaning:"'Julgados pelo Senhor somos disciplinados para não sermos condenados com o mundo' (1 Co 11:32) — a disciplina divina (formativa) é distinta da condenação (final). O crente disciplinado é preservado; o que resiste ao auto-exame acumula a necessidade de disciplina divina."),
QuizQuestion(id:987,question:"O que Paulo diz sobre a 'paz com todos' como objetivo cristão em Romanos 12:18?",options:["Evite todos os conflitos a qualquer custo","'Se possível, quanto depender de vós, tende paz com todos os homens' — o qualificador duplo: 'se possível' e 'quanto depender de vós' reconhece que a paz tem limites","A paz é impossível no mundo","Apenas com outros cristãos busque a paz"],correctIndex:1,explanation:"Romanos 12:18: a busca da paz é obrigação cristã mas tem condicionantes reais — não é possível sempre, e a responsabilidade é do crente ('quanto depender de vós'), não do resultado.",reference:"Romanos 12:18",category:.geral,propheticMeaning:"Os qualificadores ('se possível' e 'quanto depender de vós') revelam o realismo bíblico sobre a paz — o crente faz sua parte completamente, mas não pode controlar a resposta do outro. A responsabilidade é do processo, não do resultado."),
QuizQuestion(id:988,question:"O que é a 'parábola do administrador infiel' em Lucas 16 e seu ensinamento?",options:["Uma parábola aprovando a desonestidade","O administrador que usou recursos do patrão sabiamente (embora desonestamente) para garantir seu futuro; Jesus usa isso para mostrar que os 'filhos desta era' são mais habilidosos em usar recursos materiais para fins temporais do que os cristãos para fins eternos","Uma aprovação da fraude financeira","Uma história sem ensinamento"],correctIndex:1,explanation:"Lucas 16:1-13: Jesus não aprova a desonestidade, mas a astúcia e previsão — e desafia os discípulos a usar recursos ('mamona da iniquidade') para 'angariar amigos' para a eternidade.",reference:"Lucas 16:1-9",category:.geral,propheticMeaning:"'Fazei para vós amigos por meio das riquezas desta vida' (Lc 16:9) — usar recursos materiais temporais para investimentos eternos (missão, cuidado dos pobres, generosidade) é a sabedoria que Jesus recomenda. O material a serviço do eterno."),
QuizQuestion(id:989,question:"O que Paulo diz sobre 'revestir-se de Cristo' em Romanos 13:14?",options:["Uma metáfora sem sentido prático","'Revestivos do Senhor Jesus Cristo e não façais provisão para os desejos da carne' — a solução para as lutas morais não é esforço adicional mas 'colocar Cristo' como cobertura e identidade","Apenas a circuncisão resolve as lutas","O esforço moral é suficiente"],correctIndex:1,explanation:"Romanos 13:14: o antídoto para as 'obras das trevas' (v.12) não é moralismo mas a identidade — 'revestir-se de Cristo' como a armadura de luz que substitui as obras das trevas.",reference:"Romanos 13:12-14",category:.geral,propheticMeaning:"'Sem fazer provisão para a carne' — a estratégia para a vitória sobre a tentação inclui não fornecer oportunidades para ela. Não apenas resistir quando tenta mas evitar os ambientes, hábitos e estímulos que alimentam os desejos da carne."),
QuizQuestion(id:990,question:"O que Jesus diz sobre o 'julgamento começa pela casa de Deus' em 1 Pedro 4:17?",options:["A Igreja nunca é julgada","'Porque é tempo de o juízo começar pela casa de Deus; se começa por nós, qual será o fim daqueles que não obedecem ao evangelho de Deus?'","O julgamento começa pelos ímpios","A Igreja está isenta de todo julgamento"],correctIndex:1,explanation:"1 Pedro 4:17: o julgamento formativo começa pela casa de Deus (a Igreja) — o sofrimento presente dos crentes é parte da purificação que precede o julgamento final dos desobedientes.",reference:"1 Pedro 4:17",category:.geral,propheticMeaning:"O julgamento que começa pela Igreja (purificação de filhos) e que os ímpios enfrentarão (condenação de inimigos) revela a dupla face do julgamento divino — formativo para os crentes, condenatório para os que rejeitaram o evangelho."),
QuizQuestion(id:991,question:"O que Paulo diz sobre 'agradar a Deus como objetivo' em 2 Coríntios 5:9?",options:["Agrade aos homens primeiro","'Também nos esforçamos por ser-lhe agradáveis, quer presentes, quer ausentes' — a motivação do ministério: agradar a Cristo no julgamento, não a aprovação humana","Agrade à Igreja acima de tudo","A aprovação humana é necessária para o ministério"],correctIndex:1,explanation:"2 Co 5:9: 'philotimoumetha' (de amor à honra — filotimos) — o ambição apostólica de Paulo é agradar a Cristo, à luz do julgamento de todos diante do tribunal de Cristo (v.10).",reference:"2 Coríntios 5:9-10",category:.geral,propheticMeaning:"A consciência do 'tribunal de Cristo' (bema — cadeira do árbitro, não de condenação mas de avaliação das obras) transforma a motivação do ministério: não o que produz aplausos humanos mas o que recebe a aprovação do Senhor."),
QuizQuestion(id:992,question:"O que Paulo diz sobre 'tudo posso em Cristo' em Filipenses 4:13?",options:["Posso fazer qualquer coisa que queira","'Posso tudo em Cristo que me fortalece' — no contexto de contentamento em abundância e escassez (v.11-12): a capacidade de 'aguentar' todas as circunstâncias pela força de Cristo","Promessa de saúde e riqueza","Capacidade para conquistas pessoais"],correctIndex:1,explanation:"Fp 4:13: 'ischuō' (tenho força para aguentar) no contexto de 'estar abatido' e 'ter abundância' — a capacidade é para perseverar em qualquer circunstância, não para realizar qualquer ambição pessoal.",reference:"Filipenses 4:13",category:.geral,propheticMeaning:"'Tudo posso em Cristo' no contexto do contentamento (Fp 4:11) revela que o 'tudo' é a capacidade de estar contente tanto na necessidade quanto na abundância — a vitória mais difícil é sobre os próprios desejos e reações."),
QuizQuestion(id:993,question:"O que Paulo diz sobre 'gloriar-se na tribulação' em Romanos 5:3?",options:["Ignore as tribulações","'Mas também nos gloriamos nas tribulações, sabendo que a tribulação produz perseverança, e a perseverança, caráter experimentado, e o caráter experimentado, esperança'","Evite toda tribulação","As tribulações são sinal de falta de fé"],correctIndex:1,explanation:"Romanos 5:3-4: a cadeia produtiva da tribulação — não alegria masoquista no sofrimento, mas alegria na produtividade do sofrimento quando processado pela fé.",reference:"Romanos 5:3-4",category:.geral,propheticMeaning:"'Kauchōmetha en tais thlipsesin' (nos gloriamos nas tribulações) usa o mesmo verbo de 'gloriamo-nos em Deus' (v.11) — a tribulação processada pela fé torna-se tanto motivo de glória quanto Deus mesmo. O sofrimento redentor participa da glória de Deus."),
QuizQuestion(id:994,question:"O que é a 'alegria completa' em João 15:11?",options:["Felicidade sem problemas","'Estas coisas vos tenho dito para que a minha alegria esteja em vós e a vossa alegria seja completa' — a alegria de Cristo transmitida ao discípulo que permanece nele, produzida pelo amor mútuo","Alegria que vem do sucesso","Alegria que depende das circunstâncias"],correctIndex:1,explanation:"João 15:11: a 'alegria completa' (hina hē chara hymōn ē peplērōmenē) é a plenitude da alegria de Cristo habitando no discípulo — não emoção superficial mas alegria fundamentada na comunhão.",reference:"João 15:11",category:.geral,propheticMeaning:"'Minha alegria esteja em vós' — a alegria de Jesus (fundamentada na relação com o Pai — Jo 17:13) se derrama nos discípulos pela união com ele. A alegria cristã genuína é compartilhada da alegria de Cristo, não produzida por circunstâncias externas."),
QuizQuestion(id:995,question:"O que Paulo diz sobre a 'corrida sem distração' em 1 Coríntios 9:26?",options:["Corra sem direção","'Pois eu assim corro, não como para coisa incerta; assim luto, não como quem fere o ar' — a vida cristã com objetivo claro, disciplina intencional e propósito definido","Corra sem objetivo","A vida cristã é sem esforço"],correctIndex:1,explanation:"1 Co 9:26: Paulo usando as metáforas do corredor com alvo e do lutador que acerta golpes — a vida cristã tem propósito definido (Cristo), estratégia deliberada (disciplina) e resultado real (coroa).",reference:"1 Coríntios 9:26",category:.geral,propheticMeaning:"'Não como quem fere o ar' (aeroboxing — sombra boxing sem adversário) é a imagem do esforço espiritual sem objeto real — religiosidade que parece ativa mas não afronta o inimigo verdadeiro. A batalha cristã tem inimigo real, armas reais e vitória real."),
QuizQuestion(id:996,question:"O que é a 'bênção final' do livro de Judas (v.24-25)?",options:["Uma bênção pessoal de Judas","'Àquele que é poderoso para vos guardar sem tropeçar e para apresentar-vos irrepreensíveis e exultantes diante da sua glória... ao único Deus... seja glória, majestade, domínio e poder'","Uma oração pelo perdão de pecados","Uma bênção pela obediência"],correctIndex:1,explanation:"Judas 24-25: uma das mais belas doxologias do NT — a promessa de apresentação 'sem tropeçar' (aptaistos — sem quedas) e 'com exultação' (exaltante alegria) diante da glória divina.",reference:"Judas 24-25",category:.geral,propheticMeaning:"'Guardar sem tropeçar' (aptaistos) até a apresentação gloriosa revela que a perseverança final é obra de Deus, não do crente. Judas que alertou contra apóstasia conclui com a garantia de preservação divina — a tensão bíblica perfeita: vigilância humana + preservação divina."),
QuizQuestion(id:997,question:"Qual é a última bênção da Bíblia no livro de Apocalipse?",options:["'Sede santos até o fim'","'A graça do Senhor Jesus seja com todos. Amém' — a última palavra escrita da revelação canônica é graça, com a qual a Bíblia encerra o registro da auto-revelação de Deus","'Guardai os mandamentos'","'O Senhor está chegando'"],correctIndex:1,explanation:"Apocalipse 22:21: 'hē charis tou Kyriou Iēsou meta pantōn' — o fechamento do cânon com graça, igual ao início das cartas paulinas. A Bíblia abre com criação pela palavra de Deus e fecha com graça pela obra de Cristo.",reference:"Apocalipse 22:21",category:.geral,propheticMeaning:"'Graça... com TODOS' — a última palavra inclusiva do cânon: a graça de Jesus disponível a todos. Não 'com os méritos' nem 'com os merecedores' mas 'com todos' — abrindo para toda pessoa que queira receber o que Deus oferece livremente."),
QuizQuestion(id:998,question:"Qual é a mensagem central do livro de Oséias sobre o amor de Deus?",options:["Deus abandona os infiéis","O casamento de Oséias com Gômer (que o traiu) é símbolo do amor fiel de Deus por Israel apóstata — Deus continua amando e buscando seu povo mesmo na infidelidade: 'Irei após ela, e a falarei ao coração'","Deus apenas pune a infidelidade","O amor de Deus é condicional à fidelidade"],correctIndex:1,explanation:"Oséias: o amor covenantal de Deus (chesed — amor leal) por Israel apóstata, representado pelo casamento de Oséias com a prostituta Gômer. Mesmo a traição não extingue o amor divino — ele continua buscando.",reference:"Oséias 2:14; 11:8-9",category:.profetas,propheticMeaning:"'Como poderia eu entregar-te, ó Efraim?' (Os 11:8) — o lamento divino diante do julgamento necessário. Deus que ama mais do que pode julgar, mas que também é justo. A hesitação divina em executar o julgamento revela o coração do Pai que ama os filhos rebeldes."),
QuizQuestion(id:999,question:"O que Paulo ensina sobre 'a vida cristã como oferta viva' em Romanos 12:1?",options:["A vida espiritual é separada do cotidiano","'Rogo-vos, pois, irmãos, pelas misericórdias de Deus, que apresenteis os vossos corpos como sacrifício vivo, santo e agradável a Deus, que é o vosso culto racional'","Apenas os cultos são adoração","A adoração é apenas para os domingos"],correctIndex:1,explanation:"Romanos 12:1: 'logikēn latreian' (culto racional, razoável, espiritual) — toda a vida como oferta contínua de adoração, motivada pelas misericórdias de Deus (caps. 1-11).",reference:"Romanos 12:1",category:.geral,propheticMeaning:"'Pelas misericórdias de Deus' como base do chamado — a vida entregue é resposta à graça recebida, não meio de obter graça. A sequência teológica de Romanos (graça nos caps. 1-11, depois ética nos caps. 12-16) mostra: indicativo (o que Deus fez) precede imperativo (o que você deve fazer)."),
QuizQuestion(id:1000,question:"Qual é o grande tema unificador de toda a Bíblia de Gênesis a Apocalipse?",options:["A história de Israel","A história da redenção — Deus criando, a humanidade caindo, Deus prometendo (Gn 3:15), chamando (Abraão), libertando (Êxodo), encarnando (Jesus), morrendo, ressuscitando, enviando o Espírito, e criando novamente todas as coisas: o novo jardim com a árvore da vida aberta a todos","A história dos profetas","A história da lei de Moisés"],correctIndex:1,explanation:"A Bíblia tem um tema: a redenção da humanidade e da criação pelo Deus trino — Pai que planeja, Filho que realiza, Espírito que aplica. De Gênesis 1 a Apocalipse 22, é a mesma história de amor de Deus por sua criação.",reference:"Gênesis 1:1; João 3:16; Apocalipse 21:5",category:.geral,propheticMeaning:"'Estou fazendo novas todas as coisas' (Ap 21:5) é a inclusão final com Gênesis 1 ('e era muito bom') — Deus restaurando e aperfeiçoando o que criou. A Bíblia não é coleção de livros mas uma única narrativa de criação→queda→redenção→nova criação: a história mais grandiosa já contada."),
]
